namespace Geopilot.Api.Pipeline;

/// <inheritdoc />
public class PipelineFileManager : IPipelineFileManager
{
    private readonly string basePath;

    /// <summary>
    /// Create a PipelineFileManager with the specified base path for storing temporary files. The base path is used as the root directory for all temporary files generated by the pipeline.
    /// </summary>
    /// <param name="basePath">The base path for storing temporary files.</param>
    /// <param name="processorType">The type of the processor for which temporary files are being managed.</param>
    public PipelineFileManager(string basePath, Type processorType)
    {
        if (processorType != null)
        {
            this.basePath = Path.Combine(basePath, processorType?.Name != null ? processorType.Name : "Unknown");
            Directory.CreateDirectory(this.basePath);
        }
        else
        {
            this.basePath = basePath;
        }

        if (!Path.Exists(this.basePath))
            Directory.CreateDirectory(this.basePath);
    }

    /// <inheritdoc />
    public string GenerateTempFileName(string fileType, string fileExtension)
    {
        return Path.Combine(this.basePath, $"{fileType}_{Guid.NewGuid().ToString()}.{fileExtension}");
    }
}
